class Solution:
    def leastInterval(self, tasks: List[str], n: int) -> int:
        cnt = Counter(tasks); m = max(cnt.values())
        num = sum(1 for v in cnt.values() if v == m)
        return max(len(tasks), (m-1)*(n+1)+num)

