class Solution {
public:
    int leastInterval(vector<char>& tasks, int n) {
        int c[26]={}; for(char t:tasks) c[t-'A']++;
        int mx=*max_element(c,c+26), num=0;
        for(int x:c) if(x==mx) num++;
        return max((int)tasks.size(), (mx-1)*(n+1)+num);
    }
};

